  ('55555555-5555-4555-8555-555555555555', 3, 'Past Influences', 'Recent past feeding the situation.', 3, 0.3, 0.74, 0, 0, 1),
  ('55555555-5555-4555-8555-555555555555', 4, 'Receding Influences', 'What is passing away.', 4, 0.16, 0.5, 0, 0, 1),
